// // This module calculates the output Y based on the inputs A1, A2, and B1.
// The output Y is high if A1 is high and A2 is low, or if A1 is low and A2 is high,
// or if B1 is high. Otherwise, Y is low.
module my_module (
    input  A1  ,
    input  A2  ,
    input  B1  ,
    output Y   ,
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB
);

    assign Y = (A1 && !A2) || (!A1 && A2) || B1;

endmodule

